class Solution:
    def partitionLabels(self, s: str) -> list[int]:
        last = {c: i for i, c in enumerate(s)}   # 每个字母最后出现的位置
        ans, start, end = [], 0, 0
        for i, c in enumerate(s):
            end = max(end, last[c])    # 当前片段至少要延伸到 c 最后出现处
            if i == end:               # 走到片段右边界 -> 这一段可以切了
                ans.append(end - start + 1)
                start = i + 1
        return ans
